@import './theme.css';
@import './utilities.css';

.react-aria-DateRangePicker {
  color: var(--text-color);
  max-width: 100%;

  .react-aria-Group {
    display: flex;
    align-items: center;
    width: fit-content;
    min-width: 220px;
    max-width: 100%;
    height: var(--spacing-8);
    box-sizing: border-box;
    overflow: clip;
    position: relative;
    padding: 0 var(--spacing-1) 0 var(--spacing-3);
    border-radius: var(--radius);
    font-size: var(--font-size);
    color: var(--field-text-color);
    white-space: nowrap;
    cursor: text;

    &[data-focus-within] {
      outline: 2px solid var(--focus-ring-color);
      outline-offset: -1px;
    }

    &[data-disabled] {
      color: var(--text-color-disabled);
    }
  }

  .date-fields {
    flex: 1;
    display: flex;
    align-items: center;
    width: fit-content;
    overflow-x: auto;
    overflow-y: clip;
    scrollbar-width: none;
  }

  .field-Button {
    margin-left: auto;
  }

  [slot='start'] ~ span {
    padding: 0 4px;
  }

  [slot='end'] {
    margin-right: 1.75rem;
    flex: 1;
  }

  .react-aria-DateInput {
    width: unset;
    min-width: unset;
    padding: unset;
    border: unset;
    box-shadow: none;
    background: none;
    height: auto;
    line-height: normal;
    &[data-focus-within] {
      outline: unset;
    }
  }
}

@import './theme.css';

.react-aria-Disclosure {
  width: calc(var(--spacing) * 50);

  .react-aria-Heading {
    margin: 0;
  }

  .disclosure-button {
    background: none;
    border: none;
    box-shadow: none;
    text-shadow: none;
    width: 100%;
    color: var(--text-color);
    font: var(--font-size) system-ui;
    font-weight: 600;
    display: flex;
    align-items: center;
    text-align: start;
    gap: var(--spacing-1);
    padding: var(--spacing-2) var(--spacing-3);
    border-radius: var(--radius);
    transition: all 200ms;
    outline: none;
    -webkit-tap-highlight-color: transparent;

    &[data-hovered],
    &[data-pressed] {
      background: var(--gray-300);
      color: var(--text-color-hover);
    }

    &[data-pressed] {
      scale: 0.97;
    }

    &[data-focus-visible] {
      outline: 2px solid var(--focus-ring-color);
    }

    &[data-disabled] {
      color: var(--text-color-disabled);
    }

    svg {
      rotate: 0deg;
      transition: rotate 200ms;
      fill: none;
      stroke: currentColor;
      stroke-width: 3px;
    }
  }

  &[data-expanded] .disclosure-button svg {
    rotate: 90deg;
  }
}

.react-aria-DisclosurePanel {
  color: var(--text-color);
  height: var(--disclosure-panel-height);
  transition: height 250ms;
  overflow: clip;

  @media (prefers-reduced-motion: reduce) {
    transition: none;
  }

  div {
    padding: var(--spacing-2) var(--spacing-4);
  }
}

@layer components {
  .TypeRefTrigger {
    cursor: default;
    border: 0;
    background: transparent;
    padding: 0;
    border-radius: var(--radius-4);
    font: inherit;
    text-decoration: underline;
    text-decoration-thickness: 1px;
    text-decoration-style: dotted;
    text-decoration-color: color-mix(in oklab, var(--color-violet), transparent);
    text-underline-offset: 3px;

    &:hover {
      text-decoration-color: var(--color-violet);
    }

    &:focus-visible {
      outline: 2px solid var(--gray-t2);
      outline-offset: 2px;
    }
  }

  .TypeRefPopup {
    max-width: min(36rem, var(--available-width));
    overflow: visible;
  }

  .TypeRefInner {
    display: flex;
    flex-direction: column;
    max-height: var(--available-height, none);
  }

  .TypeRefArrow {
    &[data-side='bottom'] {
      top: -8px;
    }

    &[data-side='left'] {
      right: -13px;
      transform: rotate(90deg);
    }

    &[data-side='right'] {
      left: -13px;
      transform: rotate(-90deg);
    }

    &[data-side='top'] {
      bottom: -8px;
      transform: rotate(180deg);
    }
  }

  .TypeRefArrowFill {
    fill: var(--color-popup);
  }

  .TypeRefArrowStroke {
    fill: var(--blackA-3);
  }

  .TypeRefArrowStrokeDark {
    @media (prefers-color-scheme: dark) {
      fill: var(--gray-c3);
    }
  }

  @media (prefers-color-scheme: dark) {
    .TypeRefArrowStroke {
      fill: none;
    }
  }

  .TypeRefContent {
    flex: 1;
    min-height: 0;
    overflow: auto;
    scrollbar-width: auto;
  }

  .TypeRefPopup .ScrollAreaViewport {
    padding: 0.5rem 0.75rem;
  }
}
